pub async fn find(&self, name_prefix: &str) -> Result<Option<SpokeInfo>> {
        let all = self.list(true).await?;
        Ok(all.into_iter().find(|s| s.name.starts_with(name_prefix)))
    }
pub async fn create(
        &self,
        spoke_name: &str,
        agent_id: &str,
        hub: &HubContext,
        config: &CorviaConfig,
        spoke_config: &SpokeConfig,
        network: &str,
        repo_name: &str,
        repo_url: &str,
        issue: Option<u32>,
        branch_name: &str,
        workspace_root: &str,
    ) -> Result<()> {
        let span = info_span!(
            "corvia.spoke.create",
            spoke_name,
            agent_id,
            repo = repo_name,
            issue = issue.unwrap_or(0),
        );
        self.create_inner(
            spoke_name, agent_id, hub, config, spoke_config, network,
            repo_name, repo_url, issue, branch_name, workspace_root,
        )
        .instrument(span)
        .await
    }
